using UnityEngine;
using UnityEngine.UI;

public class Script {
    public static object Main() {
        // Buscar Canvas
        var canvasGO = GameObject.Find("Canvas");
        if (canvasGO == null) return "Canvas no encontrado";

        var canvasRT = canvasGO.GetComponent<RectTransform>();
        var screenWidth = canvasRT.sizeDelta.x;
        var screenHeight = canvasRT.sizeDelta.y;

        // Crear GameObject para el botón
        var btnGO = new GameObject("TopLeftButton");
        btnGO.transform.SetParent(canvasGO.transform);

        // Obtener o agregar RectTransform
        var btnRT = btnGO.GetComponent<RectTransform>();
        if (btnRT == null) btnRT = btnGO.AddComponent<RectTransform>();

        // Configurar anchor a esquina superior izquierda
        btnRT.anchorMin = new Vector2(0, 1);
        btnRT.anchorMax = new Vector2(0, 1);
        btnRT.pivot = new Vector2(0, 1);
        btnRT.anchoredPosition = Vector2.zero;

        // Tamaño: 1/3 ancho x 1/10 alto
        btnRT.sizeDelta = new Vector2(screenWidth / 3f, screenHeight / 10f);

        // Agregar Image
        var image = btnGO.AddComponent<Image>();
        image.color = Color.red;

        // Agregar Button
        var button = btnGO.AddComponent<Button>();
        var colors = button.colors;
        colors.normalColor = Color.red;
        colors.highlightedColor = Color.green;
        colors.pressedColor = new Color(0.5f, 0, 0);
        colors.disabledColor = Color.gray;
        colors.colorMultiplier = 1f;
        colors.fadeDuration = 0.1f;
        button.colors = colors;

        return $"Botón creado: {btnRT.sizeDelta}";
    }
}
